        new() { MinFhirVersion = FhirSequenceCodes.DSTU2, MaxFhirVersion = FhirSequenceCodes.R5, Name = "HumanName", Title = "Name of a human or other living entity - parts and usage", Description = "HumanName Type: A name, normally of a human, that can be used for other living entities (e.g. animals but not organizations) that have been assigned names by a human and may need the use of name parts or the need for usage information.", Comment = "Names may be changed, or repudiated, or people may have different names in different contexts. Names may be divided into parts of different type that have variable significance depending on context, though the division into parts does not always matter. With personal names, the different parts might or might not be imbued with some implicit meaning; various cultures associate different importance with the name parts and the degree to which systems must care about name parts around the world varies widely."},
