        new() { MinFhirVersion = FhirSequenceCodes.STU3, MaxFhirVersion = FhirSequenceCodes.R5, Name = "ParameterDefinition", Title = "Definition of a parameter to a module", Description = "ParameterDefinition Type: The parameters to the module. This collection specifies both the input and output parameters. Input parameters are provided by the caller as part of the $evaluate operation. Output parameters are included in the GuidanceResponse.", Comment = null},
        new() { MinFhirVersion = FhirSequenceCodes.DSTU2, MaxFhirVersion = FhirSequenceCodes.R5, Name = "Period", Title = "Time range defined by start and end date/time", Description = "Period Type: A time period defined by a start and end date and optionally time.", Comment = "A Period specifies a range of time; the context of use will specify whether the entire range applies (e.g. \"the patient was an inpatient of the hospital for this time range\") or one value from the range applies (e.g. \"give to the patient between these two times\").\n\nPeriod is not used for a duration (a measure of elapsed time). See [Duration](datatypes.html#Duration)."},
