        new() { MinFhirVersion = FhirSequenceCodes.DSTU2, MaxFhirVersion = FhirSequenceCodes.R5, Name = "Quantity", Title = "A measured or measurable amount", Description = "Quantity Type: A measured amount (or an amount that can potentially be measured). Note that measured amounts include amounts that are not precisely quantified, including amounts involving arbitrary units and floating currencies.", Comment = "The context of use may frequently define what kind of quantity this is and therefore what kind of units can be used. The context of use may also restrict the values for the comparator."},
        new() { MinFhirVersion = FhirSequenceCodes.DSTU2, MaxFhirVersion = FhirSequenceCodes.R5, Name = "Range", Title = "Set of values bounded by low and high", Description = "Range Type: A set of ordered Quantities defined by a low and high limit.", Comment = "The stated low and high value are assumed to have arbitrarily high precision when it comes to determining which values are in the range. I.e. 1.99 is not in the range 2 -> 3."},
