        new() { MinFhirVersion = FhirSequenceCodes.R4B, MaxFhirVersion = FhirSequenceCodes.R5, Name = "RatioRange", Title = "Range of ratio values", Description = "RatioRange Type: A range of ratios expressed as a low and high numerator and a denominator.", Comment = "The stated low and high value are assumed to have arbitrarily high precision when it comes to determining which values are in the range. I.e. 1.99 is not in the range 2 -> 3."},
        new() { MinFhirVersion = FhirSequenceCodes.DSTU2, MaxFhirVersion = FhirSequenceCodes.R5, Name = "Reference", Title = "A reference from one resource to another", Description = "Reference Type: A reference from one resource to another.", Comment = "References SHALL be a reference to an actual FHIR resource, and SHALL be resolvable (allowing for access control, temporary unavailability, etc.). Resolution can be either by retrieval from the URL, or, where applicable by resource type, by treating an absolute reference as a canonical URL and looking it up in a local registry/repository."},
        new() { MinFhirVersion = FhirSequenceCodes.STU3, MaxFhirVersion = FhirSequenceCodes.R5, Name = "RelatedArtifact", Title = "Related artifacts for a knowledge resource", Description = "RelatedArtifact Type: Related artifacts such as additional documentation, justification, or bibliographic references.", Comment = "Each related artifact is either an attachment, or a reference to another knowledge resource, but not both."},
        new() { MinFhirVersion = FhirSequenceCodes.DSTU2, MaxFhirVersion = FhirSequenceCodes.R5, Name = "SampledData", Title = "A series of measurements taken by a device", Description = "SampledData Type: A series of measurements taken by a device, with upper and lower limits. There may be more than one dimension in the data.", Comment = "The data is not interpretable without at least origin, period, and dimensions, but these are optional to allow a separation between the template of measurement and the actual measurement, such as between DeviceCapabilities and DeviceLog.  When providing a summary view (for example with Observation.value[x]) SampledData should be represented with a brief display text such as \"Sampled Data\"."},
        new() { MinFhirVersion = FhirSequenceCodes.DSTU2, MaxFhirVersion = FhirSequenceCodes.R5, Name = "Signature", Title = "A Signature - XML DigSig, JWS, Graphical image of signature, etc.", Description = "Signature Type: A signature along with supporting context. The signature may be a digital signature that is cryptographic in nature, or some other signature acceptable to the domain. This other signature may be as simple as a graphical image representing a hand-written signature, or a signature ceremony Different signature approaches have different utilities.", Comment = "The elements of the Signature Resource are for ease of access of these elements. For digital signatures (Xml DigSig, JWS), the non-repudiation proof comes from the Signature  validation, which includes validation of the referenced objects (e.g. Resources) (a.k.a., Content) in the XML-Signature Detached form."},
        new() { MinFhirVersion = FhirSequenceCodes.R4, MaxFhirVersion = FhirSequenceCodes.R4, Name = "SubstanceAmount", Title = "Chemical substances are a single substance type whose primary defining element is the molecular structure. Chemical substances shall be defined on the basis of their complete covalent molecular structure; the presence of a salt (counter-ion) and/or solvates (water, alcohols) is also captured. Purity, grade, physical form or particle size are not taken into account in the definition of a chemical substance or in the assignment of a Substance ID", Description = "Base StructureDefinition for SubstanceAmount Type: Chemical substances are a single substance type whose primary defining element is the molecular structure. Chemical substances shall be defined on the basis of their complete covalent molecular structure; the presence of a salt (counter-ion) and/or solvates (water, alcohols) is also captured. Purity, grade, physical form or particle size are not taken into account in the definition of a chemical substance or in the assignment of a Substance ID.", Comment = null},
        new() { MinFhirVersion = FhirSequenceCodes.DSTU2, MaxFhirVersion = FhirSequenceCodes.R5, Name = "Timing", Title = "A timing schedule that specifies an event that may occur multiple times", Description = "Timing Type: Specifies an event that may occur multiple times. Timing schedules are used to record when things are planned, expected or requested to occur. The most common usage is in dosage instructions for medications. They are also used when planning care of various kinds, and may be used for reporting the schedule to which past regular activities were carried out.", Comment = "Describes the occurrence of an event that may occur multiple times. Timing schedules are used for specifying when events are expected or requested to occur, and may also be used to represent the summary of a past or ongoing event.  For simplicity, the definitions of Timing components are expressed as 'future' events, but such components can also be used to describe historic or ongoing events.\n\nA Timing schedule can be a list of events and/or criteria for when the event happens, which can be expressed in a structured form and/or as a code. When both event and a repeating specification are provided, the list of events should be understood as an interpretation of the information in the repeat structure."},
        new() { MinFhirVersion = FhirSequenceCodes.STU3, MaxFhirVersion = FhirSequenceCodes.R5, Name = "TriggerDefinition", Title = "Defines an expected trigger for a module", Description = "TriggerDefinition Type: A description of a triggering event. Triggering events can be named events, data events, or periodic, as determined by the type element.", Comment = "If an event is a named-event, it means the event is completely pre-coordinated, and no other information can be specified for the event. If the event is one of the data- events, the data and condition elements specify the triggering criteria. The data element specifies the structured component, and the condition element provides additional optional refinement of that structured component. If the event is periodic, the timing element defines when the event is triggered. For both data- and periodic events, a name can be provided as a shorthand for the formal semantics provided by the other elements."},
        new() { MinFhirVersion = FhirSequenceCodes.STU3, MaxFhirVersion = FhirSequenceCodes.R5, Name = "UsageContext", Title = "Describes the context of use for a conformance or knowledge resource", Description = "UsageContext Type: Specifies clinical/business/etc. metadata that can be used to retrieve, index and/or categorize an artifact. This metadata can either be specific to the applicable population (e.g., age category, DRG) or the specific context of care (e.g., venue, care setting, provider of care).", Comment = null},
        new() { MinFhirVersion = FhirSequenceCodes.R5, MaxFhirVersion = FhirSequenceCodes.R5, Name = "VirtualServiceDetail", Title = "Virtual Service Contact Details", Description = "VirtualServiceDetail Type: Virtual Service Contact Details.", Comment = null},
