        new() { MinFhirVersion = FhirSequenceCodes.DSTU2, MaxFhirVersion = FhirSequenceCodes.R5, Name = "boolean", Title = "Primitive Type boolean", Description = "boolean Type: Value of \"true\" or \"false\"", Comment = null},
        new() { MinFhirVersion = FhirSequenceCodes.R4, MaxFhirVersion = FhirSequenceCodes.R5, Name = "canonical", Title = "Primitive Type canonical", Description = "canonical type: A URI that is a reference to a canonical URL on a FHIR resource", Comment = "see [Canonical References](references.html#canonical)"},
        new() { MinFhirVersion = FhirSequenceCodes.DSTU2, MaxFhirVersion = FhirSequenceCodes.R5, Name = "code", Title = "Primitive Type code", Description = "code type: A string which has at least one character and no leading or trailing whitespace and where there is no whitespace other than single spaces in the contents", Comment = "Note that FHIR strings SHALL NOT exceed 1,048,576 (1024*1024) characters in size"},
        new() { MinFhirVersion = FhirSequenceCodes.DSTU2, MaxFhirVersion = FhirSequenceCodes.R5, Name = "date", Title = "Primitive Type date", Description = "date Type: A date or partial date (e.g. just year or year + month). There is no UTC offset. The format is a union of the schema types gYear, gYearMonth and date.  Dates SHALL be valid dates.", Comment = null},
        new() { MinFhirVersion = FhirSequenceCodes.DSTU2, MaxFhirVersion = FhirSequenceCodes.R5, Name = "dateTime", Title = "Primitive Type dateTime", Description = "dateTime Type: A date, date-time or partial date (e.g. just year or year + month).  If hours and minutes are specified, a UTC offset SHALL be populated. The format is a union of the schema types gYear, gYearMonth, date and dateTime. Seconds must be provided due to schema type constraints but may be zero-filled and may be ignored.                 Dates SHALL be valid dates.", Comment = "UTC offset is allowed for dates and partial dates"},
